def check_number(num):
    if num > 0:
        return 'Positive'
    elif num < 0:
        return 'Negative'
    else:
        return 'Zero'

def check_even_odd(num):
    if num > 10:
        if num % 2 == 0:
            return 'Even and greater than 10'
        else:
            return 'Odd and greater than 10'
    return 'Not greater than 10'

def check_number(num):
    if num > 0:
        if num % 2 == 0:
            return 'Positive Even'
        else:
            return 'Positive Odd'
    elif num < 0:
        if num % 2 == 0:
            return 'Negative Even'
        else:
            return 'Negative Odd'
    else:
        return 'Zero'
